import{_ as r,o as t,c as a,ag as n}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Recurring Expenses","description":"","frontmatter":{},"headers":[],"relativePath":"features/recurring-expenses.md","filePath":"features/recurring-expenses.md"}'),i={name:"features/recurring-expenses.md"};function s(o,e,l,c,u,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="recurring-expenses" tabindex="-1">Recurring Expenses <a class="header-anchor" href="#recurring-expenses" aria-label="Permalink to &quot;Recurring Expenses&quot;">​</a></h1><p>Automate tracking of regular business costs like rent, subscriptions, and utilities.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Recurring expenses work like recurring invoices but for costs. Set up a template and let MyCompanyDesk create expense records automatically.</p><p>Common use cases:</p><ul><li>Office rent</li><li>Software subscriptions</li><li>Insurance premiums</li><li>Utility bills</li><li>Lease payments</li></ul><h2 id="creating-a-recurring-expense" tabindex="-1">Creating a recurring expense <a class="header-anchor" href="#creating-a-recurring-expense" aria-label="Permalink to &quot;Creating a recurring expense&quot;">​</a></h2><ol><li>Go to <strong>Recurring Expenses &gt; New</strong></li><li>Fill in the template: <ul><li><strong>Description</strong> — What the expense is for</li><li><strong>Amount</strong> — The recurring cost</li><li><strong>Category</strong> — Expense category</li><li><strong>VAT rate</strong> — Applicable VAT</li><li><strong>Frequency</strong> — Weekly, monthly, quarterly, or yearly</li></ul></li><li>Click <strong>Save</strong></li></ol><h2 id="frequency-options" tabindex="-1">Frequency options <a class="header-anchor" href="#frequency-options" aria-label="Permalink to &quot;Frequency options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Frequency</th><th>Description</th></tr></thead><tbody><tr><td><strong>Weekly</strong></td><td>Every 7 days</td></tr><tr><td><strong>Monthly</strong></td><td>Same day each month</td></tr><tr><td><strong>Quarterly</strong></td><td>Every 3 months</td></tr><tr><td><strong>Yearly</strong></td><td>Once per year</td></tr></tbody></table><h2 id="managing-recurring-expenses" tabindex="-1">Managing recurring expenses <a class="header-anchor" href="#managing-recurring-expenses" aria-label="Permalink to &quot;Managing recurring expenses&quot;">​</a></h2><h3 id="pause-resume" tabindex="-1">Pause / Resume <a class="header-anchor" href="#pause-resume" aria-label="Permalink to &quot;Pause / Resume&quot;">​</a></h3><p>Toggle automatic generation on or off. Pausing stops new expense creation; resuming continues from the next scheduled date.</p><h3 id="edit" tabindex="-1">Edit <a class="header-anchor" href="#edit" aria-label="Permalink to &quot;Edit&quot;">​</a></h3><p>Changes to the template affect future expenses only. Existing expenses are not modified.</p><h3 id="delete" tabindex="-1">Delete <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;Delete&quot;">​</a></h3><p>Remove the template. Previously generated expenses remain in your records.</p><h2 id="generated-expenses" tabindex="-1">Generated expenses <a class="header-anchor" href="#generated-expenses" aria-label="Permalink to &quot;Generated expenses&quot;">​</a></h2><p>Each generated expense:</p><ul><li>Matches the template&#39;s amount, category, and VAT settings</li><li>Is dated to the scheduled occurrence date</li><li>Can be edited independently after creation</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Review your recurring expenses periodically to catch cancelled subscriptions</li><li>Link recurring expenses to projects for accurate project costing</li><li>Use categories consistently for meaningful reports</li></ul>',22)])])}const h=r(i,[["render",s]]);export{g as __pageData,h as default};
